"use server"; 
import Groq from "groq-sdk";

const ai = new GoogleGenAI({ apiKey: process.env.NEXT_PUBLIC_GEMINI_TOKEN });

export async function infoRecipe(recipe: string, ingredients: string) {
  const response = await ai.models.generateContent({
    model: 'gemini-3.1-flash-lite',
    contents: [
      `Tell me the process to cook a ${recipe} utilizing ${ingredients}. It is PROHIBITED to say anything more than that.`
    ],
  });
  return response.text;
}